+
+  // Keep stdout machine-readable for the grader.  Diagnostics go to stderr.
+  std::printf("HBM_BANDWIDTH_GBPS=%.3f\n", gigabytes_per_second);
+  std::printf("buffer_bytes=%zu\n", kBufferBytes);
+
+  for (int i = 0; i < kTrials; ++i) {
+    HIP_CHECK(hipEventDestroy(starts[i]));
+    HIP_CHECK(hipEventDestroy(stops[i]));
+  }
+  HIP_CHECK(hipFree(sink));
+  HIP_CHECK(hipFree(allocation));
+  return 0;
+}
